import React from 'react';
import { FlaskConical, Code2, Bug, LayoutDashboard, ChevronRight } from 'lucide-react';

const navItems = [
  { id: 'dashboard', label: 'Dashboard', icon: LayoutDashboard },
  { id: 'testcases', label: 'Test Cases', icon: FlaskConical },
  { id: 'automation', label: 'Automation', icon: Code2 },
  { id: 'bugreports', label: 'Bug Reports', icon: Bug },
];

export default function Sidebar({ activePage, onNavigate }) {
  return (
    <aside style={{
      width: '240px',
      position: 'fixed',
      top: 0,
      left: 0,
      height: '100vh',
      background: '#fff',
      borderRight: '1px solid #e2e8f0',
      display: 'flex',
      flexDirection: 'column',
      zIndex: 100,
      boxShadow: '2px 0 12px rgba(26,86,219,0.06)',
    }}>
      {/* Logo */}
      <div style={{
        padding: '20px',
        background: 'linear-gradient(135deg, #1a56db 0%, #3b82f6 100%)',
      }}>
        <div style={{ display: 'flex', alignItems: 'center', gap: '10px' }}>
          <div style={{
            width: 36,
            height: 36,
            background: 'rgba(255,255,255,0.2)',
            borderRadius: 10,
            display: 'flex',
            alignItems: 'center',
            justifyContent: 'center',
            backdropFilter: 'blur(4px)',
          }}>
            <FlaskConical size={18} color="white" />
          </div>
          <div>
            <div style={{ fontWeight: 700, fontSize: 15, color: '#fff', lineHeight: 1.2 }}>QA Assistant</div>
            <div style={{ fontSize: 11, color: 'rgba(255,255,255,0.7)', marginTop: 1 }}>AI-Powered Testing</div>
          </div>
        </div>
      </div>

      {/* Nav */}
      <nav style={{ padding: '14px 10px', flex: 1 }}>
        <div style={{
          fontSize: 10,
          fontWeight: 700,
          textTransform: 'uppercase',
          letterSpacing: '0.08em',
          color: '#94a3b8',
          padding: '4px 10px 10px',
        }}>
          Main Menu
        </div>
        {navItems.map(({ id, label, icon: Icon }) => {
          const active = activePage === id;
          return (
            <button
              key={id}
              onClick={() => onNavigate(id)}
              style={{
                display: 'flex',
                alignItems: 'center',
                gap: 10,
                width: '100%',
                padding: '10px 12px',
                borderRadius: 8,
                border: 'none',
                cursor: 'pointer',
                fontSize: 13,
                fontWeight: active ? 600 : 400,
                color: active ? '#1a56db' : '#475569',
                background: active ? '#eff6ff' : 'transparent',
                marginBottom: 3,
                textAlign: 'left',
                transition: 'all 0.15s',
                borderLeft: active ? '3px solid #1a56db' : '3px solid transparent',
              }}
              onMouseEnter={e => { if (!active) { e.currentTarget.style.background = '#f8faff'; e.currentTarget.style.color = '#1a56db'; } }}
              onMouseLeave={e => { if (!active) { e.currentTarget.style.background = 'transparent'; e.currentTarget.style.color = '#475569'; } }}
            >
              <Icon size={16} />
              <span style={{ flex: 1 }}>{label}</span>
              {active && <ChevronRight size={13} />}
            </button>
          );
        })}
      </nav>

      {/* Footer */}
      <div style={{ padding: '14px 16px', borderTop: '1px solid #e2e8f0' }}>
        <div style={{
          background: '#eff6ff',
          border: '1px solid #bfdbfe',
          borderRadius: 8,
          padding: '10px 12px',
        }}>
          <div style={{ fontSize: 12, fontWeight: 700, color: '#1a56db' }}>Phase 1 · Active</div>
          <div style={{ fontSize: 11, color: '#3b82f6', marginTop: 2 }}>Core QA features enabled</div>
        </div>
        <div style={{ marginTop: 10, fontSize: 11, color: '#94a3b8', textAlign: 'center' }}>
          Powered by Gemini AI
        </div>
      </div>
    </aside>
  );
}
